/**
 * PromptVault — Full Health Check Script
 * Run with: npx ts-node -r tsconfig-paths/register scratch/healthcheck.ts
 * Or:       npx tsx scratch/healthcheck.ts
 */

import dotenv from 'dotenv';
import path from 'path';

dotenv.config({ path: path.resolve(process.cwd(), '.env.local') });

// ─── Helpers ────────────────────────────────────────────────────────────────

const PASS  = '✅ PASS';
const FAIL  = '❌ FAIL';
const WARN  = '⚠️  WARN';
const SKIP  = '⏭️  SKIP';

let totalPass = 0, totalFail = 0, totalWarn = 0;

function ok(label: string, detail = '') {
  totalPass++;
  console.log(`  ${PASS}  ${label}${detail ? ` — ${detail}` : ''}`);
}
function fail(label: string, detail = '') {
  totalFail++;
  console.log(`  ${FAIL}  ${label}${detail ? `\n         → ${detail}` : ''}`);
}
function warn(label: string, detail = '') {
  totalWarn++;
  console.log(`  ${WARN}  ${label}${detail ? `\n         → ${detail}` : ''}`);
}
function section(title: string) {
  console.log(`\n${'─'.repeat(60)}`);
  console.log(`  ${title}`);
  console.log('─'.repeat(60));
}

// ─── 1. Environment Variables ────────────────────────────────────────────────

section('1. Environment Variables');

// Vercel-injected Supabase vars (new integration names)
const VERCEL_SUPABASE_VARS = [
  'SUPABASEE_SUPABASE_URL',
  'NEXT_PUBLIC_SUPABASEE_SUPABASE_ANON_KEY',
  'SUPABASEE_SUPABASE_SERVICE_ROLE_KEY',
];

// Alias vars that the codebase reads — must be resolvable
const REQUIRED_VARS = [
  'NEXT_PUBLIC_SUPABASE_URL',
  'NEXT_PUBLIC_SUPABASE_ANON_KEY',
  'SUPABASE_URL',
  'SUPABASE_KEY',
  'OPENROUTER_API_KEY',
  'NEXT_PUBLIC_SITE_URL',
];

const OPTIONAL_VARS = [
  'GOOGLE_CLIENT_ID',
  'GOOGLE_CLIENT_SECRET',
  'SUPABASE_SERVICE_ROLE_KEY',
  'SUPABASEE_POSTGRES_URL',
];

console.log('\n  — Vercel Integration Vars —');
for (const v of VERCEL_SUPABASE_VARS) {
  const val = process.env[v];
  if (!val || val === 'PASTE_VALUE_HERE') {
    fail(v, 'Not filled in — copy value from Vercel → Storage → .env.local tab');
  } else {
    ok(v, `${val.slice(0, 30)}...`);
  }
}
console.log('\n  — Alias Vars (used by codebase) —');

for (const v of REQUIRED_VARS) {
  const val = process.env[v];
  if (!val) {
    fail(v, 'MISSING — this will break the app');
  } else if (val.includes('YOUR_') || val.includes('PLACEHOLDER')) {
    warn(v, 'looks like a placeholder value');
  } else {
    ok(v, `${val.slice(0, 30)}...`);
  }
}

for (const v of OPTIONAL_VARS) {
  const val = process.env[v];
  if (!val) {
    warn(v, 'not set (optional but may affect auth/server features)');
  } else {
    ok(v, `${val.slice(0, 20)}...`);
  }
}

// Validate Supabase URL format
const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL ?? '';
if (supabaseUrl && !supabaseUrl.match(/^https:\/\/[a-z]+\.supabase\.co$/)) {
  warn('NEXT_PUBLIC_SUPABASE_URL format', `Unexpected format: ${supabaseUrl}`);
}

// ─── 2. Supabase Connectivity ────────────────────────────────────────────────

section('2. Supabase Connectivity');

async function checkSupabase() {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

  if (!url || !key) {
    fail('Supabase connection', 'Missing URL or anon key — skipping all DB checks');
    return false;
  }

  // Ping the Supabase REST endpoint
  try {
    const res = await fetch(`${url}/rest/v1/`, {
      headers: { apikey: key, Authorization: `Bearer ${key}` },
    });
    if (res.ok || res.status === 200) {
      ok('Supabase REST API reachable', `Status ${res.status}`);
    } else {
      fail('Supabase REST API', `HTTP ${res.status} — check your URL and anon key`);
      return false;
    }
  } catch (e: any) {
    fail('Supabase REST API unreachable', e.message);
    return false;
  }

  return true;
}

// ─── 3. Database Tables ──────────────────────────────────────────────────────

section('3. Database Tables');

const EXPECTED_TABLES = ['prompts', 'prompt_versions', 'test_cases', 'evaluations'];

async function checkTables(reachable: boolean) {
  if (!reachable) {
    console.log(`  ${SKIP}  Skipped — Supabase not reachable`);
    return;
  }

  const url = process.env.NEXT_PUBLIC_SUPABASE_URL!;
  const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

  for (const table of EXPECTED_TABLES) {
    try {
      const res = await fetch(`${url}/rest/v1/${table}?limit=1`, {
        headers: {
          apikey: key,
          Authorization: `Bearer ${key}`,
          'Content-Type': 'application/json',
          Prefer: 'count=none',
        },
      });

      if (res.status === 200) {
        ok(`Table: ${table}`, 'exists and accessible');
      } else if (res.status === 401 || res.status === 403) {
        // RLS blocking unauthenticated = tables EXIST, RLS working correctly
        warn(`Table: ${table}`, `HTTP ${res.status} — RLS blocking anon access (this is CORRECT behaviour)`);
      } else if (res.status === 404) {
        fail(`Table: ${table}`, 'TABLE MISSING — run server/database.sql in Supabase SQL editor');
      } else {
        const body = await res.text();
        warn(`Table: ${table}`, `HTTP ${res.status}: ${body.slice(0, 100)}`);
      }
    } catch (e: any) {
      fail(`Table: ${table}`, e.message);
    }
  }
}

// ─── 4. OpenRouter AI ────────────────────────────────────────────────────────

section('4. OpenRouter AI (Prompt Evaluation)');

async function checkOpenRouter() {
  const apiKey = process.env.OPENROUTER_API_KEY;
  if (!apiKey) {
    fail('OpenRouter API key', 'MISSING — evaluation will not work');
    return;
  }

  try {
    const res = await fetch('https://openrouter.ai/api/v1/chat/completions', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
        'HTTP-Referer': 'https://promptvault.vercel.app',
      },
      body: JSON.stringify({
        model: 'openai/gpt-4o-mini',
        messages: [{ role: 'user', content: 'Reply with exactly: {"ok":true}' }],
        response_format: { type: 'json_object' },
        max_tokens: 20,
      }),
    });

    if (res.status === 200) {
      const data = await res.json();
      const content = data?.choices?.[0]?.message?.content;
      ok('OpenRouter API', `Responded: ${content?.slice(0, 50)}`);
    } else if (res.status === 401) {
      fail('OpenRouter API key', 'Invalid API key — get a new one from openrouter.ai');
    } else if (res.status === 402) {
      warn('OpenRouter API', 'Insufficient credits — top up at openrouter.ai');
    } else if (res.status === 429) {
      warn('OpenRouter API', 'Rate limited — try again in a moment');
    } else {
      const body = await res.text();
      fail('OpenRouter API', `HTTP ${res.status}: ${body.slice(0, 150)}`);
    }
  } catch (e: any) {
    fail('OpenRouter API', `Network error: ${e.message}`);
  }
}

// ─── 5. App Pages (Local Dev) ────────────────────────────────────────────────

section('5. App Pages (requires `npm run dev` running)');

const BASE = process.env.NEXT_PUBLIC_SITE_URL ?? 'http://localhost:3000';

const PAGES = [
  { path: '/',              name: 'Landing Page' },
  { path: '/how-it-works', name: 'How it Works' },
  { path: '/features',     name: 'Features' },
  { path: '/pricing',      name: 'Pricing' },
  { path: '/login',        name: 'Login' },
  { path: '/demo',         name: 'Demo (redirects if unauthed)' },
  { path: '/privacy',      name: 'Privacy Policy' },
  { path: '/security',     name: 'Security' },
  { path: '/eula',         name: 'EULA' },
];

async function checkPages() {
  for (const page of PAGES) {
    try {
      const res = await fetch(`${BASE}${page.path}`, {
        redirect: 'follow',
        signal: AbortSignal.timeout(5000),
      });

      if (res.status === 200) {
        ok(`${page.path}`, `${page.name} — OK`);
      } else if (res.status === 307 || res.status === 302) {
        warn(`${page.path}`, `${page.name} — redirected (expected for auth-protected pages)`);
      } else {
        fail(`${page.path}`, `${page.name} — HTTP ${res.status}`);
      }
    } catch (e: any) {
      if (e.name === 'TimeoutError' || e.code === 'ECONNREFUSED') {
        warn(`${page.path}`, `${page.name} — dev server not running (start with: npm run dev)`);
      } else {
        fail(`${page.path}`, e.message);
      }
    }
  }
}

// ─── 6. API Endpoint ─────────────────────────────────────────────────────────

section('6. Express API Endpoint');

async function checkApi() {
  try {
    const res = await fetch(`${BASE}/api/`, {
      signal: AbortSignal.timeout(5000),
    });
    if (res.ok) {
      ok('/api/', `HTTP ${res.status}`);
    } else {
      warn('/api/', `HTTP ${res.status} — may be expected if no root handler`);
    }
  } catch (e: any) {
    if (e.code === 'ECONNREFUSED') {
      warn('/api/', 'Dev server not running');
    } else {
      fail('/api/', e.message);
    }
  }
}

// ─── Run All Checks ──────────────────────────────────────────────────────────

(async () => {
  console.log('\n🔍 PromptVault Health Check');
  console.log(`   Base URL: ${BASE}`);
  console.log(`   Time:     ${new Date().toISOString()}`);

  const supabaseReachable = await checkSupabase();
  await checkTables(supabaseReachable);
  await checkOpenRouter();
  await checkPages();
  await checkApi();

  // ─── Summary ────────────────────────────────────────────────────────────
  section('Summary');
  console.log(`  ✅ Passed : ${totalPass}`);
  console.log(`  ⚠️  Warnings: ${totalWarn}`);
  console.log(`  ❌ Failed : ${totalFail}`);
  console.log();

  if (totalFail > 0) {
    console.log('  Fix the ❌ failures above before deploying.\n');
    process.exit(1);
  } else if (totalWarn > 0) {
    console.log('  App should work but review ⚠️  warnings.\n');
  } else {
    console.log('  Everything looks great! 🚀\n');
  }
})();

import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
import rateLimit from 'express-rate-limit';
import evalRoutes from './routes/evals';
import { errorHandler } from './middleware/errorHandler';

export function createApp() {
  const app = express();

  // Basic security and setup
  app.use(helmet());
  app.use(cors({
    origin: '*', // Allow all for demo purposes, can be restricted via config
  }));

  const apiLimiter = rateLimit({
    windowMs: 15 * 60 * 1000,
    max: 100,
    standardHeaders: true,
    legacyHeaders: false,
  });

  const evalLimiter = rateLimit({
    windowMs: 60 * 60 * 1000,
    max: 50,
    standardHeaders: true,
    legacyHeaders: false,
    message: { error: 'Eval rate limit exceeded. Wait a moment before running more evaluations.' },
  });

  app.use(express.json({ limit: '5mb' }));

  // The demo now only requires the stateless evaluation API
  // All prompt/version management is handled locally in the browser
  app.use('/api/evals', evalLimiter, evalRoutes);

  app.use((_req, res) => {
    res.status(404).json({ error: 'Not found' });
  });

  app.use(errorHandler);

  return app;
}

import { Request, Response, NextFunction } from 'express';
import { ZodError } from 'zod';
import { AppError } from '../lib/errors';

const isDev = process.env.NODE_ENV !== 'production';

/**
 * Global error handling middleware.
 * Prevents information disclosure by returning generic error messages
 * to the client while logging detailed errors internally.
 */
export function errorHandler(
  err: unknown,
  req: Request,
  res: Response,
  _next: NextFunction
) {
  const normalizedError = normalizeError(err);
  const statusCode = normalizedError.statusCode;

  // Log the error internally
  console.error(`[Error] ${req.method} ${req.url}:`, {
    message: normalizedError.message,
    code: normalizedError.code,
    stack: isDev ? normalizedError.stack : undefined,
    timestamp: new Date().toISOString(),
  });

  // Sanitized response for the client
  res.status(statusCode).json({
    error: isDev ? normalizedError.message : getSanitizedMessage(statusCode),
    code: normalizedError.code,
    // In production, we don't send the stack trace
    ...(isDev && { stack: normalizedError.stack }),
  });
}

function normalizeError(err: unknown) {
  if (err instanceof AppError) {
    return err;
  }

  if (err instanceof ZodError) {
    return new AppError(err.issues.map((issue) => issue.message).join('; '), 400, 'validation_error');
  }

  if (err instanceof SyntaxError && 'body' in err) {
    return new AppError('Invalid JSON payload.', 400, 'invalid_json');
  }

  if (err instanceof Error) {
    return new AppError(err.message, 500, 'internal_error');
  }

  return new AppError('An internal server error occurred.', 500, 'internal_error');
}

function getSanitizedMessage(statusCode: number): string {
  switch (statusCode) {
    case 400: return 'Bad request.';
    case 401: return 'Unauthorized.';
    case 403: return 'Forbidden.';
    case 404: return 'Resource not found.';
    case 429: return 'Too many requests.';
    default: return 'An internal server error occurred.';
  }
}

