import axios from 'axios';
import { env } from '../config/env';

export class SearchService {
  /**
   * Performs a Google Search and returns formatted snippets to be injected as RAG context.
   */
  static async performGrounding(query: string) {
    if (!env.GOOGLE_SEARCH_API_KEY || !env.GOOGLE_SEARCH_CX) {
      console.warn("Search API keys missing. Returning mocked grounding data.");
      return `[LIVE GOOGLE SEARCH CONTEXT]\n- Google Search (Mock): Found 3 related articles for "${query}" regarding recent developments.\n[/CONTEXT]`;
    }

    try {
      const url = `https://www.googleapis.com/customsearch/v1?key=${env.GOOGLE_SEARCH_API_KEY}&cx=${env.GOOGLE_SEARCH_CX}&q=${encodeURIComponent(query)}&num=3`;
      const response = await axios.get(url);

      if (!response.data.items || response.data.items.length === 0) {
         return "[LIVE GOOGLE SEARCH CONTEXT]\nNo recent information found.\n[/CONTEXT]";
      }

      const snippets = response.data.items.map((i: any) => `- ${i.title}: ${i.snippet}`).join('\n');
      return `[LIVE GOOGLE SEARCH CONTEXT]\n${snippets}\n[/CONTEXT]`;
    } catch (error) {
      console.error('Search API failed:', error);
      throw new Error('Grounding search failed during external API request.');
    }
  }
}

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { localHistory, LocalPrompt } from '../../utils/localHistory';
import {
  analyzePromptAction,
  improvePromptAction,
  runMultiModelEvalAction,
  AnalysisResult,
} from './actions';

export interface EvalResult {
  model: string;
  status: 'success' | 'error';
  data?: {
    actual_output: string;
    score: number | null;
    judgement_reason: string | null;
  };
  error?: string;
}

const DEFAULT_PROMPT = "Act as a senior technical SEO content strategist. Your objective is to create a high-impact, 1000-word blog post optimized for specific long-tail keywords.\n\nKey Instructions:\n1. Tone: Professional yet accessible, using the inverted pyramid style.\n2. Structure: Include a hook-driven introduction, at least four H2 subheadings, and a clear CTA.\n3. Entities: Naturally integrate related semantic terms without keyword stuffing.\n4. Formatting: Use bullet points for readability.";

function getErrorMessage(error: unknown) {
  return error instanceof Error ? error.message : 'Unexpected error';
}

export function usePromptManager() {
  const router = useRouter();
  const [promptText, setPromptText] = useState(DEFAULT_PROMPT);
  const [metrics, setMetrics] = useState<AnalysisResult | null>(null);
  const [evalResults, setEvalResults] = useState<EvalResult[] | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isImproving, setIsImproving] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [isEvaluating, setIsEvaluating] = useState(false);
  const [activeTab, setActiveTab] = useState<'editor'|'search'|'analytics'|'eval'>('editor');
  const [searchQuery, setSearchQuery] = useState("");
  const [savedPrompts, setSavedPrompts] = useState<LocalPrompt[]>([]);
  const [selectedPromptId, setSelectedPromptId] = useState<string | null>(null);
  const [selectedPromptName, setSelectedPromptName] = useState('Unsaved Prompt');
  const [selectedVersionNumber, setSelectedVersionNumber] = useState<number | null>(null);

  useEffect(() => {
    refreshSavedPrompts();
  }, [activeTab]);

  const refreshSavedPrompts = () => {
    setSavedPrompts(localHistory.getPrompts());
  };

  const handleCreatePrompt = () => {
    setSelectedPromptId(null);
    setSelectedPromptName('Unsaved Prompt');
    setSelectedVersionNumber(null);
    setPromptText(DEFAULT_PROMPT);
    setMetrics(null);
    setEvalResults(null);
    setActiveTab('editor');
  };

  const handleSelectPrompt = (prompt: LocalPrompt) => {
    const latestVersion = prompt.prompt_versions[0] ?? null;

    setSelectedPromptId(prompt.id);
    setSelectedPromptName(prompt.name);
    setSelectedVersionNumber(latestVersion?.version_num ?? null);
    setPromptText(latestVersion?.content ?? '');
    setMetrics(latestVersion?.analysis_metrics ?? null);
    setEvalResults(null);
    setActiveTab('editor');
  };

  const handleSave = async () => {
    if (!promptText.trim()) return;
    setIsSaving(true);
    try {
      const savedPrompt = localHistory.savePrompt(
        promptText,
        selectedPromptId,
        metrics?.overall,
        metrics
      );

      setSelectedPromptId(savedPrompt.id);
      setSelectedPromptName(savedPrompt.name);
      setSelectedVersionNumber(savedPrompt.prompt_versions[0].version_num);
      refreshSavedPrompts();
      alert("Prompt saved to local history!");
    } catch (error: unknown) {
      alert("Failed to save: " + getErrorMessage(error));
    } finally {
      setIsSaving(false);
    }
  };

  const handleAnalyze = async () => {
    if (!promptText.trim()) return;
    setIsAnalyzing(true);
    try {
      const res = await analyzePromptAction(promptText);
      setMetrics(res);
    } catch (error: unknown) {
      alert("Failed to analyze: " + getErrorMessage(error));
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleImprove = async () => {
    if (!promptText.trim()) return;
    setIsImproving(true);
    try {
      const res = await improvePromptAction(promptText);
      setPromptText(res.improvedPrompt);
    } catch (error: unknown) {
      alert("Failed to improve: " + getErrorMessage(error));
    } finally {
      setIsImproving(false);
    }
  };

  const handleMultiModelEval = async () => {
    if (!promptText.trim()) return;
    setIsEvaluating(true);
    setActiveTab('eval');
    try {
      const models = [
        'openai/gpt-4o',
        'anthropic/claude-3.5-sonnet',
        'google/gemini-pro-1.5'
      ];
      const res = await runMultiModelEvalAction(promptText, models);
      setEvalResults(res);
    } catch (error: unknown) {
      alert("Evaluation failed: " + getErrorMessage(error));
    } finally {
      setIsEvaluating(false);
    }
  };

  const handleExport = () => {
    const data = localHistory.exportHistory();
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `vaultprompt-history-${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleImport = async (file: File) => {
    try {
      const text = await file.text();
      localHistory.importHistory(text);
      refreshSavedPrompts();
      alert('Prompts imported successfully!');
    } catch (e) {
      alert(e instanceof Error ? e.message : 'Import failed');
    }
  };

  return {
    promptText, setPromptText,
    metrics, setMetrics,
    evalResults,
    isAnalyzing, isImproving, isSaving, isEvaluating,
    activeTab, setActiveTab,
    searchQuery, setSearchQuery,
    savedPrompts,
    selectedPromptId,
    selectedPromptName,
    selectedVersionNumber,
    handleCreatePrompt,
    handleSelectPrompt,
    handleSave, handleAnalyze, handleImprove,
    handleMultiModelEval,
    handleExport,
    handleImport
  };
}

'use client';

import React, { useEffect, useState, useCallback, useMemo } from 'react';
import styles from './Vault.module.css';
import { localHistory, LocalPrompt } from '@/utils/localHistory';

export default function VaultClient() {
  const [prompts, setPrompts] = useState<LocalPrompt[]>([]);
  const [activePromptId, setActivePromptId] = useState<string | null>(null);
  const [draftContent, setDraftContent] = useState('');
  const [isEvaluating, setIsEvaluating] = useState(false);
  const [isImproving, setIsImproving] = useState(false);
  const [evalResults, setEvalResults] = useState<any[]>([]);
  const [useGrounding, setUseGrounding] = useState(false);
  const [toxicity, setToxicity] = useState<number | null>(null);
  const [isAuditing, setIsAuditing] = useState(false);

  useEffect(() => {
    // Load from local storage
    const history = localHistory.getPrompts();
    setPrompts(history);
    if (history.length > 0) {
      setActivePromptId(history[0].id);
      setDraftContent(history[0].prompt_versions[0].content);
    }
  }, []);

  const handleSelectPrompt = useCallback((p: LocalPrompt) => {
    setActivePromptId(p.id);
    setDraftContent(p.prompt_versions[0].content);
    setEvalResults([]);
    setToxicity(null);
  }, []);

  const handleNew = () => {
    setActivePromptId(null);
    setDraftContent('');
    setEvalResults([]);
    setToxicity(null);
  };

  const handleSave = () => {
    if (!draftContent.trim()) return;
    const newPrompt = localHistory.savePrompt(draftContent, activePromptId);
    setPrompts(localHistory.getPrompts());
    setActivePromptId(newPrompt.id);
  };

  const handleEvaluate = async () => {
    if (!draftContent.trim()) return;
    setIsEvaluating(true);
    setEvalResults([]);
    try {
      // Connect to the local unproxied backend port 3001
      const res = await fetch('http://localhost:3001/api/evals/run-direct', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          content: draftContent,
          models: ['gemini-1.5-pro-latest'], // Hardcoded to test
          expected_output: "A structured event itinerary with a timeline, session recommendations, and 2 actionable networking icebreakers.",
          useGrounding
        })
      });
      const data = await res.json();
      setEvalResults(data);
      if (activePromptId) {
        // Save evaluation to history
        const score = data[0]?.data?.score || null;
        localHistory.savePrompt(draftContent, activePromptId, score, data[0]?.data);
        setPrompts(localHistory.getPrompts());
      }
    } catch (err) {
      console.error(err);
      alert('Failed to evaluate prompt. Make sure the proxy server is running.');
    } finally {
      setIsEvaluating(false);
    }
  };

  const handleImproveWithAI = async () => {
    if (!draftContent.trim()) return;
    setIsImproving(true);
    try {
      const res = await fetch('http://localhost:3001/api/evals/improve', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: draftContent })
      });
      const data = await res.json();
      if (data.improved_prompt) {
        setDraftContent(data.improved_prompt);
        // Automatically save the improved version
        const newPrompt = localHistory.savePrompt(data.improved_prompt, activePromptId);
        setPrompts(localHistory.getPrompts());
        setActivePromptId(newPrompt.id);
        alert('Event query refined by AI! See changes in the editor.');
      }
    } catch (err) {
      console.error(err);
      alert('AI Query Refiner failed. Please try again.');
    } finally {
      setIsImproving(false);
    }
  };

  const handleSafetyAudit = async () => {
    if (!draftContent.trim()) return;
    setIsAuditing(true);
    setToxicity(null);
    try {
      const res = await fetch('http://localhost:3001/api/evals/safety', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ content: draftContent })
      });
      const data = await res.json();
      setToxicity(data.toxicity);
    } catch (err) {
      console.error(err);
      alert('Safety audit failed. Ensure Perspective API logic is running.');
    } finally {
      setIsAuditing(false);
    }
  };

  return (
    <div className={styles.vaultContainer}>
      <aside className={styles.sidebar}>
        <button className={`${styles.button} ${styles.primaryBtn}`} onClick={handleNew}>+ New Draft</button>
        <h3>Local History</h3>
        {prompts.map(p => (
          <button 
            key={p.id} 
            className={styles.historyItem}
            onClick={() => handleSelectPrompt(p)}
            style={{ 
              borderColor: p.id === activePromptId ? '#a855f7' : 'transparent', 
              borderWidth: '1px', 
              borderStyle: 'solid',
              textAlign: 'left',
              width: '100%',
              display: 'block',
              background: p.id === activePromptId ? 'rgba(168, 85, 247, 0.1)' : 'transparent'
            }}
            aria-current={p.id === activePromptId ? 'true' : 'false'}
          >
            <h4>{p.name}</h4>
            <p>{new Date(p.updated_at).toLocaleDateString()}</p>
          </button>
        ))}
        {prompts.length === 0 && <p style={{opacity: 0.5, fontSize: '0.8rem'}}>No saved plans.</p>}
      </aside>

      <div className={styles.mainArea}>
        <div className={styles.editorSection}>
          <h2 style={{marginTop: 0, marginBottom: '15px'}}>Event Needs</h2>
          <textarea 
            className={styles.textarea}
            value={draftContent}
            onChange={e => setDraftContent(e.target.value)}
            placeholder="e.g., I have 1 hour free, what’s worth attending?"
            aria-label="Event Query Input"
          />
          <div style={{display: 'flex', gap: '15px', marginBottom: '15px', alignItems: 'center'}}>
            <label style={{display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.9rem', cursor: 'pointer'}}>
              <input type="checkbox" checked={useGrounding} onChange={(e) => setUseGrounding(e.target.checked)} />
              Ground with Google Search
            </label>
            <button 
              className={styles.button} 
              onClick={handleSafetyAudit}
              disabled={isAuditing || !draftContent}
              style={{background: 'rgba(255,255,255,0.1)', padding: '6px 12px', fontSize: '0.9rem'}}
            >
              {isAuditing ? 'Auditing...' : '🛡️ Safety Audit (Perspective)'}
            </button>
            {toxicity !== null && (
              <span style={{fontSize: '0.9rem', fontWeight: 'bold', color: toxicity > 50 ? '#ef4444' : '#22c55e'}}>
                Toxicity: {toxicity}%
              </span>
            )}
          </div>
          <div className={styles.actionRow}>
            <button className={styles.button} onClick={handleSave}>Save Locally</button>
            <button 
              className={`${styles.button} ${styles.aiBtn}`} 
              onClick={handleImproveWithAI}
              disabled={isImproving || !draftContent}
              aria-label="Refine Query with AI"
            >
              {isImproving ? 'Refining...' : '✨ Refine Query (AI)'}
            </button>
            <button 
              className={`${styles.button} ${styles.primaryBtn}`} 
              onClick={handleEvaluate}
              disabled={isEvaluating || !draftContent}
              aria-label="Generate Event Plan"
            >
              {isEvaluating ? 'Generating...' : 'Generate Event Plan (Gemini)'}
            </button>
          </div>
        </div>

        <div className={styles.resultsSection}>
          <h2 style={{marginTop: 0, marginBottom: '15px'}}>Your Personal Itinerary</h2>
          {evalResults.length === 0 && <p style={{opacity: 0.5}}>Generate an event plan to see your schedule.</p>}

          {evalResults.map((res: any, i: number) => (
            <div key={i} className={styles.evalCard}>
              <h3>Model: {res.model}</h3>
              {res.status === 'success' ? (
                <>
                  <div className={`${styles.score} ${res.data.score < 4 ? styles.badScore : ''}`}>
                    Itinerary Completeness Rating: {res.data.score}/5
                  </div>
                  <div className={styles.reasoning}>Why: {res.data.judgement_reason}</div>
                  <div style={{marginTop: '15px', background: 'rgba(0,0,0,0.5)', padding: '10px', borderRadius: '4px'}}>
                    <strong>Output:</strong>
                    <pre style={{whiteSpace: 'pre-wrap', fontFamily: 'inherit', margin: 0}}>{res.data.actual_output}</pre>
                  </div>
                </>
              ) : (
                <div className={styles.badScore}>Evaluation Error: {res.error}</div>
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export interface LocalPromptVersion {
  id: string;
  content: string;
  version_num: number;
  analysis_score: number | null;
  analysis_metrics: any | null;
  tags: string[];
  created_at: string;
}

export interface LocalPrompt {
  id: string;
  name: string;
  created_at: string;
  updated_at: string;
  prompt_versions: LocalPromptVersion[];
}

const STORAGE_KEY = 'vaultprompt_history';

export const localHistory = {
  getPrompts(): LocalPrompt[] {
    if (typeof window === 'undefined') return [];
    const stored = localStorage.getItem(STORAGE_KEY);
    if (!stored) return [];
    try {
      const parsed = JSON.parse(stored) as LocalPrompt[];
      // Sort by updated_at desc
      return parsed.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime());
    } catch (e) {
      console.error('Failed to parse local history:', e);
      return [];
    }
  },

  savePrompt(content: string, promptId?: string | null, analysisScore?: number, analysisMetrics?: any): LocalPrompt {
    const prompts = this.getPrompts();
    const now = new Date().toISOString();

    if (promptId) {
      const existingIdx = prompts.findIndex(p => p.id === promptId);
      if (existingIdx !== -1) {
        const prompt = prompts[existingIdx];
        const nextVersionNum = Math.max(...prompt.prompt_versions.map(v => v.version_num), 0) + 1;
        
        const newVersion: LocalPromptVersion = {
          id: crypto.randomUUID(),
          content,
          version_num: nextVersionNum,
          analysis_score: analysisScore ?? null,
          analysis_metrics: analysisMetrics ?? null,
          tags: [],
          created_at: now
        };

        prompt.prompt_versions.unshift(newVersion);
        prompt.updated_at = now;
        
        prompts[existingIdx] = prompt;
        this.persist(prompts);
        return prompt;
      }
    }

    // Create new prompt
    const newPrompt: LocalPrompt = {
      id: crypto.randomUUID(),
      name: content.split('\n')[0].trim().slice(0, 60) || `New Prompt ${new Date().toLocaleDateString()}`,
      created_at: now,
      updated_at: now,
      prompt_versions: [{
        id: crypto.randomUUID(),
        content,
        version_num: 1,
        analysis_score: analysisScore ?? null,
        analysis_metrics: analysisMetrics ?? null,
        tags: [],
        created_at: now
      }]
    };

    prompts.unshift(newPrompt);
    this.persist(prompts);
    return newPrompt;
  },

  updateTags(promptId: string, versionNum: number, tags: string[]): LocalPrompt | null {
    const prompts = this.getPrompts();
    const promptIdx = prompts.findIndex(p => p.id === promptId);
    if (promptIdx === -1) return null;

    const versionIdx = prompts[promptIdx].prompt_versions.findIndex(v => v.version_num === versionNum);
    if (versionIdx === -1) return null;

    prompts[promptIdx].prompt_versions[versionIdx].tags = tags;
    this.persist(prompts);
    return prompts[promptIdx];
  },

  deletePrompt(id: string): void {
    const prompts = this.getPrompts().filter(p => p.id !== id);
    this.persist(prompts);
  },

  exportHistory(): string {
    const prompts = this.getPrompts();
    return JSON.stringify(prompts, null, 2);
  },

  importHistory(jsonData: string): void {
    try {
      const imported = JSON.parse(jsonData) as LocalPrompt[];
      if (!Array.isArray(imported)) throw new Error('Invalid format');
      
      const current = this.getPrompts();
      const currentIds = new Set(current.map(p => p.id));
      
      // Merge: only add prompts that don't already exist by ID
      const toAdd = imported.filter(p => !currentIds.has(p.id));
      this.persist([...current, ...toAdd]);
    } catch (e) {
      console.error('Import failed:', e);
      throw new Error('Failed to import: Invalid JSON file format.');
    }
  },

  persist(prompts: LocalPrompt[]): void {
    if (typeof window !== 'undefined') {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(prompts));
    }
  }
};
